const email = $input.first().json;

return [{
  json: {
    source: "gmail",
    dedup_key: email.id,
    event_type: "email_incoming"
  }
}];

const email = $('Gmail Trigger').first().json;
const dedup = $('Deduplicate').first().json;

// Extract sender
const sender = email.from || '';
const subject = email.subject || '(no subject)';

// Get body text, strip HTML if needed
let body = email.textPlain || email.text || '';
if (!body && email.textHtml) {
  body = email.textHtml.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
}
if (!body && email.html) {
  body = email.html.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
}

// Truncate body to prevent token overflow (first 3000 chars)
const truncatedBody = body.length > 3000
  ? body.substring(0, 3000) + '...'
  : body;

return [{
  json: {
    // Email metadata
    sender: sender,
    subject: subject,
    body: truncatedBody,
    receivedDate: email.date || new Date().toISOString(),
    messageId: email.id || '',
    threadId: email.threadId || '',
    hasAttachments: Array.isArray(email.attachments) && email.attachments.length > 0,
    event_id: dedup.event_id,
    // AI call parameters (passed through to UTIL__AICall)
    prompt: `Classify the following email.\n\nFrom: ${sender}\nSubject: ${subject}\nBody: ${truncatedBody}\n\nRespond with valid JSON only (no markdown, no code fences):\n{\n  "category": "<one of: inquiry, support, sales, internal, urgent, spam>",\n  "urgency": "<one of: high, medium, low>",\n  "confidence": <number 0.0 to 1.0>,\n  "summary": "<brief 1-sentence summary>",\n  "suggested_department": "<one of: sales, support, engineering, management, hr>"\n}`,
    system_message: "You are an email classifier for a business operations system. Analyze the email and classify it accurately. Be conservative with urgency — only mark 'high' for time-sensitive matters. Always respond with valid JSON only.",
    model_preference: "fast",
    output_format: "json"
  }
}];

const aiResponse = $input.first().json;
const metadata = $('Extract Metadata').first().json;

// Parse the AI classification response
let classification;
try {
  const responseText = aiResponse.response || aiResponse.text || JSON.stringify(aiResponse);
  // Clean potential markdown code fences
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classification = typeof cleaned === 'object' ? cleaned : JSON.parse(cleaned);
} catch (e) {
  // Fallback if parsing fails
  classification = {
    category: 'internal',
    urgency: 'medium',
    confidence: 0.0,
    summary: 'Classification failed — manual review required',
    suggested_department: 'support'
  };
}

// Validate and normalize
const validCategories = ['inquiry', 'support', 'sales', 'internal', 'urgent', 'spam'];
const validUrgencies = ['high', 'medium', 'low'];
const validDepts = ['sales', 'support', 'engineering', 'management', 'hr'];

const category = validCategories.includes(classification.category)
  ? classification.category : 'internal';
const urgency = validUrgencies.includes(classification.urgency)
  ? classification.urgency : 'medium';
const confidence = typeof classification.confidence === 'number'
  ? Math.max(0, Math.min(1, classification.confidence)) : 0.0;
const suggested_department = validDepts.includes(classification.suggested_department)
  ? classification.suggested_department : 'support';

return [{
  json: {
    // Email metadata (carried forward)
    sender: metadata.sender,
    subject: metadata.subject,
    body: metadata.body,
    receivedDate: metadata.receivedDate,
    messageId: metadata.messageId,
    threadId: metadata.threadId,
    hasAttachments: metadata.hasAttachments,
    event_id: metadata.event_id,
    // Classification results
    category: category,
    urgency: urgency,
    confidence: confidence,
    summary: classification.summary || '',
    suggested_department: suggested_department,
    // Full classification object for storage
    classification: {
      category, urgency, confidence,
      summary: classification.summary || '',
      suggested_department
    },
    // AI metadata
    model_used: aiResponse.model_used || null,
    ai_tokens_input: aiResponse.tokens_input || null,
    ai_tokens_output: aiResponse.tokens_output || null,
    ai_latency_ms: aiResponse.latency_ms || null
  }
}];

const data = $('Parse Classification').first().json;

// Map department to Slack channel
// Initially all go to #email-routing — expand per-department later
const departmentChannels = {
  sales: '#email-routing',
  support: '#email-routing',
  engineering: '#email-routing',
  management: '#email-routing',
  hr: '#email-routing'
};

const urgencyEmoji = {
  high: '🔴',
  medium: '🟡',
  low: '🟢'
};

const channel = departmentChannels[data.suggested_department] || '#email-routing';
const emoji = urgencyEmoji[data.urgency] || '⚪';

return [{
  json: {
    channel: channel,
    message: `📧 *New Email Classified*\n*From:* ${data.sender}\n*Subject:* ${data.subject}\n*Category:* ${data.category}\n*Urgency:* ${emoji} ${data.urgency} (confidence: ${(data.confidence * 100).toFixed(0)}%)\n*Department:* ${data.suggested_department}\n*Summary:* ${data.summary}`
  }
}];

const data = $('Parse Classification').first().json;

// Flag this email for human review due to low AI confidence
return [{
  json: {
    flagged: true,
    reason: 'low_confidence',
    confidence: data.confidence,
    event_id: data.event_id,
    sender: data.sender,
    subject: data.subject,
    category: data.category,
    message: `⚠️ Low confidence classification (${(data.confidence * 100).toFixed(0)}%) needs human review.\nFrom: ${data.sender}\nSubject: ${data.subject}\nCategory: ${data.category}`
  }
}];

const data = $('Parse Classification').first().json;

// Prepare input for EMAIL__GenerateDraft sub-workflow
return [{
  json: {
    email_body: data.body,
    email_subject: data.subject,
    sender: data.sender,
    classification: data.classification,
    threadId: data.threadId,
    messageId: data.messageId,
    event_id: data.event_id
  }
}];

const data = $('Parse Classification').first().json;

// Prepare audit log input
return [{
  json: {
    workflow_name: "EMAIL__ClassifyIncoming",
    execution_id: $execution.id,
    log_type: "action",
    action: "email_classified",
    input_payload: {
      sender: data.sender,
      subject: data.subject,
      messageId: data.messageId
    },
    output_payload: data.classification,
    model: data.model_used,
    tokens_input: data.ai_tokens_input,
    tokens_output: data.ai_tokens_output,
    latency_ms: data.ai_latency_ms,
    status: "success"
  }
}];
